public static <T> T[] addAll(T[] array1, T... array2) {
    if (array1 == null && array2 == null) {
        return null;
    } else if (array1 == null) {
        return clone(array2);
    } else if (array2 == null) {
        return clone(array1);
    }
    final Class<?> type1 = array1.getClass().getComponentType();
    final Class<?> type2 = array2.getClass().getComponentType();
    if (!type1.isAssignableFrom(type2) && !type2.isAssignableFrom(type1)) {
        throw new IllegalArgumentException("Incompatible array types: " + type1.getName() + " and " + type2.getName());
    }
    final Class<?> commonType = type1.isAssignableFrom(type2) ? type1 : type2;
    int length1 = array1.length;
    int length2 = array2.length;
    T[] joinedArray = (T[]) Array.newInstance(commonType, length1 + length2);
    System.arraycopy(array1, 0, joinedArray, 0, length1);
    System.arraycopy(array2, 0, joinedArray, length1, length2);
    return joinedArray;
}
